// Build a list of {owner, repo} from the search result + filter to:
//   - updated in last 24h
//   - NOT empty (Gitea returns 409 on /commits for empty repos)
const items = $json.data || [];
const cutoff = Date.now() - 24*60*60*1000;
const keep = [];
for (const r of items) {
  if (r.empty) continue;
  if (new Date(r.updated_at).getTime() >= cutoff) {
    keep.push({json: {owner: r.owner.login, repo: r.name, full: r.full_name, updated: r.updated_at}});
  }
}
return keep;

// n8n's HTTP Request node auto-splits array responses, so each item
// here is a SINGLE commit object (not an array of commits per repo).
// Group by repo, filter on date, then render.
const cutoff = Date.now() - 24*60*60*1000;
const byRepo = {};

for (const item of $input.all()) {
  const c = item.json;
  if (!c || c.error) continue;
  const dateStr = c.created || c.commit?.author?.date;
  if (!dateStr) continue;
  if (new Date(dateStr).getTime() < cutoff) continue;
  // Resolve repo name: prefer .repository.full_name, fall back to URL parse
  let repoName = c.repository?.full_name;
  if (!repoName) {
    const m = (c.url || '').match(/\/api\/v1\/repos\/([^\/]+)\/([^\/]+)\//);
    if (m) repoName = `${m[1]}/${m[2]}`;
  }
  if (!repoName) repoName = 'unknown';
  (byRepo[repoName] = byRepo[repoName] || []).push(c);
}

const lines = [];
let repoCount = 0;
let commitCount = 0;
for (const [repoName, commits] of Object.entries(byRepo)) {
  repoCount++;
  lines.push(`**${repoName}** (${commits.length} commit${commits.length>1?'s':''})`);
  for (const c of commits.slice(0, 5)) {
    const msg = (c.commit?.message || c.message || '').split('\n')[0].slice(0, 90);
    const who = c.commit?.author?.name || c.author?.login || 'unknown';
    lines.push(`  • ${msg} — _${who}_`);
    commitCount++;
  }
  if (commits.length > 5) lines.push(`  • …and ${commits.length-5} more`);
}

let text;
if (!lines.length) {
  text = ':sleeping: No Gitea activity in the last 24 hours.';
} else {
  text = `:newspaper: **Daily Gitea digest** — ${commitCount} commits across ${repoCount} repo${repoCount>1?'s':''}\n\n${lines.join('\n')}`;
}

return [{json: {text}}];
